{"code": "import json

# Get the book details
book_details = locals()['var_functions.query_db:28']

# Get the high rated books data for ratings
high_rated_books = locals()['var_functions.query_db:22']

# Create a dictionary for easy lookup of ratings
rating_lookup = {book['book_id']: {'avg_rating': float(book['avg_rating']), 'review_count': int(book['review_count'])} for book in high_rated_books}

# Prepare the final result - filter for children's books that have high ratings
final_books = []
for book in book_details:
    book_id = book['book_id']
    if book_id in rating_lookup:
        final_books.append({
            'title': book['title'],
            'book_id': book_id,
            'average_rating': round(rating_lookup[book_id]['avg_rating'], 2),
            'review_count': rating_lookup[book_id]['review_count'],
            'category': book['categories']
        })

# Sort by average rating (descending) then by title
final_books.sort(key=lambda x: (-x['average_rating'], x['title']))

print('__RESULT__:')
print(json.dumps({
    'total_books_found': len(final_books),
    'books': final_books
}, indent=2))"}

